// Extract ROSA pricing from AWS pricing API response
const pricingData = $input.first().json;

// Parse instance pricing
const instancePricing = {};
const products = pricingData.products || {};
const terms = pricingData.terms?.OnDemand || {};

for (const [sku, product] of Object.entries(products)) {
  if (product.productFamily === 'Compute Instance') {
    const instanceType = product.attributes?.instanceType;
    if (instanceType) {
      // Find pricing in terms
      const pricing = terms[sku];
      if (pricing) {
        const priceData = Object.values(pricing)[0];
        const priceDimensions = Object.values(priceData.priceDimensions)[0];
        instancePricing[instanceType] = {
          hourly: parseFloat(priceDimensions.pricePerUnit.USD),
          monthly: parseFloat(priceDimensions.pricePerUnit.USD) * 730,
          vcpu: parseInt(product.attributes?.vcpu || 0),
          memory: product.attributes?.memory
        };
      }
    }
  }
}

return {
  json: {
    rosaControlPlane: 0.03, // ROSA control plane cost per hour
    instances: instancePricing,
    lastUpdated: new Date().toISOString()
  }
};

